diff --git a/src/Carbon/Traits/Boundaries.php b/src/Carbon/Traits/Boundaries.php
index b21b9c5..a37e6af 100644
--- a/src/Carbon/Traits/Boundaries.php
+++ b/src/Carbon/Traits/Boundaries.php
@@ -109,9 +109,27 @@ trait Boundaries
      */
     public function startOfQuarter()
     {
-        $month = ($this->quarter - 1) * static::MONTHS_PER_QUARTER + 1;
+        /** @var CarbonInterface $this */
+        $fiscalStart = $this->localFiscalYearStartMonth ?? 1;

-        return $this->setDate($this->year, $month, 1)->startOfDay();
+        if ($fiscalStart === 1) {
+            $month = ($this->quarter - 1) * static::MONTHS_PER_QUARTER + 1;
+            return $this->setDate($this->year, $month, 1)->startOfDay();
+        }
+
+        $currentMonth = $this->month;
+        $fiscalMonth = (($currentMonth - $fiscalStart + 12) % 12) + 1;
+        $fiscalQuarterOffset = (int) floor(($fiscalMonth - 1) / 3) * 3;
+        $startMonthOfQuarter = (($fiscalStart - 1 + $fiscalQuarterOffset) % 12) + 1;
+        $year = $this->year;
+        if ($startMonthOfQuarter > $currentMonth) { $year--; }
+        return $this->setDate($year, $startMonthOfQuarter, 1)->startOfDay();
     }
